        String html = "<span>XML</span>";
        String baseUri = "";
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(html, baseUri, parser);
        assertEquals("<span>XML</span>", doc.body().html());
        assertEquals(baseUri, doc.baseUri());
    }

